import React from 'react'
// import * as Leaflet from 'leaflet'
import { MapContainer, TileLayer, Marker } from 'react-leaflet'
import MarkerPin from "./dolen-pin.png"

// var MarkerIcon = Leaflet.icon({
//   iconUrl: MarkerPin
// });

const StadiaTileLayer = () => {
  return (
    <TileLayer
      url="https://tiles.stadiamaps.com/tiles/alidade_smooth_dark/{z}/{x}/{y}{r}.png"
      attribution='© <a href="https://stadiamaps.com/">Stadia Maps</a>, © <a href="https://openmaptiles.org/">OpenMapTiles</a> © <a href="http://openstreetmap.org">OpenStreetMap</a> contributors'
    />
  );
}

const DolnaMap = ({ pubs }) => {
  const center = [42.6890335, 23.3265247]
  if (typeof window !== 'undefined') {
    return (
      <MapContainer
       center={center}
       zoom={13}
       className="h-full min-h-full min-h-full-page"
       >
        <StadiaTileLayer/>
        {pubs.map(pub => (
          <Marker
            key={pub.node.id}
            // icon={MarkerIcon}
            position={[pub.node.Latitude, pub.node.Longitude ]}
            eventHandlers={{
              click: () => {
                console.log('marker clicked')
              },
            }}
          />
          ))
        }
      </MapContainer>
    )
  }
  return null
}

const PubMap = ({ lat, lng }) => {
  const pubCoords = [lat, lng]
  if (typeof window !== 'undefined') {
    return (
      <MapContainer center={pubCoords} zoom={15} className="h-full">
        <StadiaTileLayer/>
        <Marker
          // icon={MarkerIcon}
          position={pubCoords} />
      </MapContainer>
    )
  }
  return null
}

export { DolnaMap, PubMap }
